# Print help for getQsList operation
#
##############################################################################
print_getQsList_help() {
    echo ""
    echo -e "${BOLD}${WHITE}getQsList - List QuickServers${OFF}${BLUE}(AUTH - )${OFF}${BLUE}(AUTH - HEADER)${OFF}${BLUE}(AUTH - HEADER)${OFF}" | paste -sd' ' - | fold -sw 80 | sed '2,$s/^/    /'
    echo -e ""
    echo -e "Returns the QuickServer services on your account. Use the 'qs_id' values with '/qs/{id}' for details or with the action endpoints (restart, backup, etc.) to manage each server." | paste -sd' ' - | fold -sw 80
    echo -e ""
    echo ""
    echo -e "${BOLD}${WHITE}Responses${OFF}"
    code=200
    echo -e "${result_color_table[${code:0:1}]}  200;The listing of 'Quickservers' services on your account.${OFF}" | paste -sd' ' - | column -t -s ';' | fold -sw 80 | sed '2,$s/^/       /'
    code=401
    echo -e "${result_color_table[${code:0:1}]}  401;Unauthorized${OFF}" | paste -sd' ' - | column -t -s ';' | fold -sw 80 | sed '2,$s/^/       /'
}
